using System.Collections.Generic;
using System.Globalization;
using System.Text;

/// <summary>Tipo de efeito visual animado aplicado a um intervalo de caracteres.</summary>
public enum DialogueEffectType
{
    /// <summary>O texto treme.</summary>
    Shake,

    /// <summary>O texto fica destacado, com a cor a pulsar/animar.</summary>
    Highlight
}

/// <summary>
/// Um efeito visual aplicado a um intervalo de caracteres VISÍVEIS (índices
/// que correspondem directamente a TMP_TextInfo.characterInfo da página).
/// </summary>
public struct DialogueEffectRange
{
    public DialogueEffectType type;

    /// <summary>Índice do primeiro carácter afectado (inclusive).</summary>
    public int startIndex;

    /// <summary>Índice a seguir ao último carácter afectado (exclusive).</summary>
    public int endIndex;
}

/// <summary>Uma pausa do efeito de escrita antes de revelar o carácter "charIndex".</summary>
public struct DialogueWaitPoint
{
    public int charIndex;
    public float seconds;
}

/// <summary>Uma "página" de diálogo já processada, pronta a atribuir a um TMP_Text.</summary>
public class DialogueParsedPage
{
    /// <summary>Texto pronto a atribuir a TMP_Text.text (tags TMP nativas preservadas, tags próprias removidas).</summary>
    public string displayText = string.Empty;

    /// <summary>Número de caracteres visíveis (igual ao TMP_TextInfo.characterCount desta página).</summary>
    public int visibleCharCount;

    public List<DialogueEffectRange> effects = new List<DialogueEffectRange>();
    public List<DialogueWaitPoint> waits = new List<DialogueWaitPoint>();
}

/// <summary>
/// Faz o parsing das tags próprias do sistema de diálogo dentro do texto de
/// uma DialogueLine.
///
/// Tags suportadas (usam parêntesis rectos para não colidir com as tags
/// nativas do TMP, que usam &lt;&gt; e passam directamente para o texto final):
///
///   [wait=0.5]                   - pausa o efeito de escrita 0.5s neste ponto
///   [shake]...[/shake]           - o texto entre as tags treme
///   [highlight]...[/highlight]   - o texto entre as tags fica destacado (cor animada)
///   [page] (ou [p])               - termina o balão actual; o player tem de
///                                   premir o botão de interação para continuar
///                                   o resto do texto num balão "novo"
///
/// Tags nativas do TMP continuam a funcionar normalmente dentro do texto,
/// por exemplo: &lt;b&gt;negrito&lt;/b&gt;, &lt;i&gt;itálico&lt;/i&gt;,
/// &lt;u&gt;sublinhado&lt;/u&gt;, &lt;size=150%&gt;maior&lt;/size&gt;,
/// &lt;color=#FFD700&gt;cor&lt;/color&gt;.
/// </summary>
public static class DialogueMarkupParser
{
    public static List<DialogueParsedPage> Parse(string raw)
    {
        var pages = new List<DialogueParsedPage>();
        var page = new DialogueParsedPage();

        var output = new StringBuilder();
        int visibleIndex = 0;

        int shakeStart = -1;
        int highlightStart = -1;

        if (string.IsNullOrEmpty(raw))
        {
            pages.Add(page);
            return pages;
        }

        int i = 0;
        while (i < raw.Length)
        {
            char c = raw[i];

            // Tag nativa do TMP (<b>, <color=...>, etc.) - passa directamente, não conta como carácter visível.
            if (c == '<')
            {
                int close = raw.IndexOf('>', i);
                if (close < 0)
                {
                    output.Append(c);
                    visibleIndex++;
                    i++;
                    continue;
                }

                output.Append(raw, i, close - i + 1);
                i = close + 1;
                continue;
            }

            // Tag própria do sistema de diálogo.
            if (c == '[')
            {
                int close = raw.IndexOf(']', i);
                if (close < 0)
                {
                    output.Append(c);
                    visibleIndex++;
                    i++;
                    continue;
                }

                string tag = raw.Substring(i + 1, close - i - 1).Trim();
                i = close + 1;

                string tagLower = tag.ToLowerInvariant();

                if (tagLower.StartsWith("wait"))
                {
                    float seconds = 0.5f;
                    int eq = tag.IndexOf('=');
                    if (eq >= 0 && float.TryParse(tag.Substring(eq + 1).Trim(), NumberStyles.Float, CultureInfo.InvariantCulture, out var parsed))
                        seconds = parsed;

                    page.waits.Add(new DialogueWaitPoint { charIndex = visibleIndex, seconds = seconds });
                }
                else if (tagLower == "shake")
                {
                    shakeStart = visibleIndex;
                }
                else if (tagLower == "/shake")
                {
                    if (shakeStart >= 0)
                    {
                        page.effects.Add(new DialogueEffectRange { type = DialogueEffectType.Shake, startIndex = shakeStart, endIndex = visibleIndex });
                        shakeStart = -1;
                    }
                }
                else if (tagLower == "highlight")
                {
                    highlightStart = visibleIndex;
                }
                else if (tagLower == "/highlight")
                {
                    if (highlightStart >= 0)
                    {
                        page.effects.Add(new DialogueEffectRange { type = DialogueEffectType.Highlight, startIndex = highlightStart, endIndex = visibleIndex });
                        highlightStart = -1;
                    }
                }
                else if (tagLower == "page" || tagLower == "p")
                {
                    // Fecha efeitos que tenham ficado abertos no fim da página.
                    CloseOpenEffects(page, ref shakeStart, ref highlightStart, visibleIndex);

                    page.displayText = output.ToString();
                    page.visibleCharCount = visibleIndex;
                    pages.Add(page);

                    page = new DialogueParsedPage();
                    output = new StringBuilder();
                    visibleIndex = 0;
                }
                else
                {
                    // Tag desconhecida: trata como texto normal (incluindo os parêntesis).
                    string raw2 = "[" + tag + "]";
                    output.Append(raw2);
                    visibleIndex += raw2.Length;
                }

                continue;
            }

            output.Append(c);
            visibleIndex++;
            i++;
        }

        CloseOpenEffects(page, ref shakeStart, ref highlightStart, visibleIndex);

        page.displayText = output.ToString();
        page.visibleCharCount = visibleIndex;
        pages.Add(page);

        return pages;
    }

    /// <summary>Fecha [shake]/[highlight] que tenham ficado sem tag de fecho até ao fim da página actual.</summary>
    private static void CloseOpenEffects(DialogueParsedPage page, ref int shakeStart, ref int highlightStart, int endIndex)
    {
        if (shakeStart >= 0)
        {
            page.effects.Add(new DialogueEffectRange { type = DialogueEffectType.Shake, startIndex = shakeStart, endIndex = endIndex });
            shakeStart = -1;
        }

        if (highlightStart >= 0)
        {
            page.effects.Add(new DialogueEffectRange { type = DialogueEffectType.Highlight, startIndex = highlightStart, endIndex = endIndex });
            highlightStart = -1;
        }
    }
}
